import{_ as t,o as l,c as r,a0 as i}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Import Lifecycle Tests","description":"","frontmatter":{},"headers":[],"relativePath":"testing/import-tests.md","filePath":"testing/import-tests.md"}'),a={name:"testing/import-tests.md"};function s(o,e,c,n,d,p){return l(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="import-lifecycle-tests" tabindex="-1">Import Lifecycle Tests <a class="header-anchor" href="#import-lifecycle-tests" aria-label="Permalink to &quot;Import Lifecycle Tests&quot;">​</a></h1><p>Use these tests to confirm the full safe-import lifecycle for each import type.</p><h2 id="test-1-wrong-alliance-context-guard" tabindex="-1">Test 1. Wrong alliance context guard <a class="header-anchor" href="#test-1-wrong-alliance-context-guard" aria-label="Permalink to &quot;Test 1. Wrong alliance context guard&quot;">​</a></h2><ol><li>Open the Imports page with a role that can upload alliance member screenshots. Expected result: the page opens normally.</li><li>Choose the <strong>Alliance players / member list</strong> import type. Expected result: alliance context is required.</li><li>Leave alliance unselected and try to continue. Expected result: the flow is blocked until an alliance is selected.</li><li>Select an alliance and try again. Expected result: the upload flow becomes valid.</li></ol><h2 id="test-2-alliance-player-import-lifecycle" tabindex="-1">Test 2. Alliance player import lifecycle <a class="header-anchor" href="#test-2-alliance-player-import-lifecycle" aria-label="Permalink to &quot;Test 2. Alliance player import lifecycle&quot;">​</a></h2><ol><li>Upload a valid alliance member screenshot. Expected result: the import reaches review and no live player data is written yet.</li><li>Edit one staging row before accepting. Expected result: only the staging row changes.</li><li>Accept one row. Expected result: the row moves to a saved state and the player record is updated or created.</li><li>Verify the player in the directory. Expected result: the written player data matches the accepted row.</li><li>Use <strong>Delete import &amp; rollback</strong>. Expected result: the import moves to <code>rolled_back</code>.</li><li>Verify the rollback outcome. Expected result: results created by this import are removed; overwritten values are only restored where the documented rollback rules allow it; unrelated newer data is left intact.</li><li>Restore the import from the Recycle Bin. Expected result: the import returns as <code>restored_draft</code>.</li><li>Re-open the review page and accept again. Expected result: the live changes can be written again from the restored draft.</li></ol><h2 id="test-3-event-result-screenshot-lifecycle" tabindex="-1">Test 3. Event-result screenshot lifecycle <a class="header-anchor" href="#test-3-event-result-screenshot-lifecycle" aria-label="Permalink to &quot;Test 3. Event-result screenshot lifecycle&quot;">​</a></h2><ol><li>Upload a valid event-result screenshot into an unlocked instance. Expected result: the import reaches review and no live result is written yet.</li><li>Edit one row in review. Expected result: only the staging row changes.</li><li>Accept one row. Expected result: a live result is written for that player and event context.</li><li>Verify the result on the instance or player view. Expected result: the saved result is visible.</li><li>Delete the import with rollback. Expected result: the import becomes <code>rolled_back</code>.</li><li>Verify the result state. Expected result: the import-created result is removed, while unrelated data stays intact.</li><li>Restore from the Recycle Bin. Expected result: the import returns as <code>restored_draft</code>.</li><li>Accept the row again. Expected result: the result is written again.</li></ol><h2 id="test-4-spreadsheet-lifecycle" tabindex="-1">Test 4. Spreadsheet lifecycle <a class="header-anchor" href="#test-4-spreadsheet-lifecycle" aria-label="Permalink to &quot;Test 4. Spreadsheet lifecycle&quot;">​</a></h2><ol><li>Upload a valid spreadsheet file. Expected result: the spreadsheet enters the same review-first flow.</li><li>Edit one staging row. Expected result: only the staging row changes.</li><li>Accept one row. Expected result: the corresponding live player or result update is written.</li><li>Delete the import with rollback. Expected result: the import becomes <code>rolled_back</code>.</li><li>Restore the import. Expected result: it returns as <code>restored_draft</code>.</li><li>Re-accept the row. Expected result: the live change can be written again.</li></ol><h2 id="test-5-locked-session-rejection" tabindex="-1">Test 5. Locked-session rejection <a class="header-anchor" href="#test-5-locked-session-rejection" aria-label="Permalink to &quot;Test 5. Locked-session rejection&quot;">​</a></h2><ol><li>Try to accept or import into a locked event instance. Expected result: the write is blocked with <strong>&quot;This event instance is locked. Request unlock or ask a leader to unlock it.&quot;</strong></li></ol>',12)])])}const m=t(a,[["render",s]]);export{u as __pageData,m as default};
